// Margin Guardrail: checks if opportunity margin >= target
const GHL_TOKEN = '{{ghl_token}}';
const LOCATION_ID = '{{ghl_location_id}}';
const MARGIN_FIELD = '{{ghl_cf_gross_margin_pct}}';
const MARGIN_TARGET = {{margin_target}};
const BASE = 'https://services.leadconnectorhq.com';
const HEADERS = {
  'Authorization': `Bearer ${GHL_TOKEN}`,
  'Version': '2021-07-28',
  'Content-Type': 'application/json'
};

const body = $input.first().json;
const oppId = body.opportunity_id || body.id;

if (!oppId) return [{ json: { status: 'error', message: 'No opportunity ID provided' } }];

// Fetch opportunity
const resp = await fetch(`${BASE}/opportunities/${oppId}`, { headers: HEADERS });
const opp = await resp.json();

// Find margin field
const marginField = (opp.customFields || []).find(f => f.id === MARGIN_FIELD);
const margin = parseFloat(marginField?.value) || 0;

if (margin < MARGIN_TARGET) {
  return [{ json: {
    status: 'flagged',
    opportunity_id: oppId,
    name: opp.name,
    margin: margin,
    target: MARGIN_TARGET,
    message: `Margin ${margin}% is below ${MARGIN_TARGET}% target`
  }}];
}

return [{ json: { status: 'ok', opportunity_id: oppId, margin, target: MARGIN_TARGET } }];
